mapper.select:
SELECT wc.*, t.table_number, u.username, h.username AS handler_name FROM waiter_call wc LEFT JOIN table_info t ON wc.table_id = t.table_id LEFT JOIN `user` u ON wc.user_id = u.user_id LEFT JOIN `user` h ON wc.handled_by = h.user_id
AND wc.status = #{status}
ORDER BY wc.call_time DESC

mapper.update:
UPDATE waiter_call
SET status = 'HANDLED',
    handled_time = NOW(),
    handled_by = #{handledBy}
WHERE call_id = #{callId}
  AND status = 'PENDING'
